public void registerHandlingEvent( LocalDateTime completionTime, TrackingId trackingId, VoyageNumber voyageNumber, UnLocode unLocode, HandlingEvent.Type type) throws CannotCreateHandlingEventException {
    if (trackingId == null) {
        throw new CannotCreateHandlingEventException("TrackingId cannot be null");
    }
    if (voyageNumber == null) {
        throw new CannotCreateHandlingEventException("VoyageNumber cannot be null");
    }
    if (unLocode == null) {
        throw new CannotCreateHandlingEventException("UnLocode cannot be null");
    }
    if (completionTime.isAfter(LocalDateTime.now())) {
        throw new CannotCreateHandlingEventException("Completion time cannot be in the future");
    }

    if (type == null || type == HandlingEvent.Type.values()[HandlingEvent.Type.values().length - 1]) {
        throw new CannotCreateHandlingEventException("Handling event type is invalid");
    }

    LocalDateTime registrationTime = LocalDateTime.now();
    HandlingEvent event = handlingEventFactory.createHandlingEvent(registrationTime, completionTime, trackingId, voyageNumber, unLocode, type);
    handlingEventRepository.store(event);
    applicationEvents.cargoWasHandled(event);
    logger.info("Handling event registered: " + event);
}
